# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from flask import Flask, request, jsonify
import subprocess
import boto3
import os

app = Flask(__name__)

# Configuration
THUMBNAIL_SIZE = (120, 80)
S3_BUCKET_NAME = 'your-s3-bucket-name'
CHROME_PATH = '/usr/bin/google-chrome-stable'

@app.route('/screenshot', methods=['POST'])
def take_screenshot():
    url = request.form.get('url')
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    # Generate thumbnail using headless Chrome
    screenshot_path = '/tmp/screenshot.png'
    command = [
        CHROME_PATH,
        '--headless',
        f'--window-size=1920x1080',
        f'--screenshot={screenshot_path}',
        f'--disable-software-rasterizer',
        url
    ]
    subprocess.run(command, check=True)

    # Resize thumbnail to specified size
    command = [
        'convert',
        screenshot_path,
        '-resize', f'{THUMBNAIL_SIZE[0]}x{THUMBNAIL_SIZE[1]}',
        '/tmp/resized_screenshot.png'
    ]
    subprocess.run(command, check=True)

    # Upload screenshot to S3
    s3 = boto3.client('s3')
    s3.upload_file('/tmp/resized_screenshot.png', S3_BUCKET_NAME, os.path.basename(screenshot_path))

    return jsonify({'message': 'Screenshot generated and uploaded successfully'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)